1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_RATE = 0.1;
14	
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	const COMPONENT_TYPES = ["rune", "moonstone"];
25	const COMPONENTS_PER_BLOCK = 3;
26	const COMPONENT_BLOCK_BASE = 60;
27	const CURSE_SURCHARGE_RATE = 0.5;
28	const HIGH_ENCHANTMENT_THRESHOLD = 5;
29	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
30	
31	export function quote(_customer: Customer, items: Item[]): number {
32	  const percentageSurcharge = (rate: number, applies: (item: Item) => boolean): number =>
33	    items.reduce((sum, item) => sum + (applies(item) ? BASE_PREMIUMS[item.type] * rate : 0), 0);
34	
35	  const baseSum = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
36	  // A block of exactly COMPONENTS_PER_BLOCK alike components (same type) replaces their summed base with COMPONENT_BLOCK_BASE.
37	  const blockAdjustment = COMPONENT_TYPES.reduce((adjustment, componentType) => {
38	    const count = items.filter((item) => item.type === componentType).length;
39	    const replacement = COMPONENT_BLOCK_BASE - COMPONENTS_PER_BLOCK * BASE_PREMIUMS[componentType];
40	    return count === COMPONENTS_PER_BLOCK ? adjustment + replacement : adjustment;
41	  }, 0);
42	  const curseSurcharge = percentageSurcharge(CURSE_SURCHARGE_RATE, (item) => item.cursed === true);
43	  const highEnchantmentSurcharge = percentageSurcharge(
44	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
45	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
46	  );
47	  const adjustedBase = baseSum + blockAdjustment;
48	  const firstInsurance = adjustedBase * FIRST_INSURANCE_RATE;
49	  return Math.ceil(adjustedBase + curseSurcharge + highEnchantmentSurcharge + firstInsurance + PROCESSING_FEE);
50	}
